import React, { useEffect, useState } from 'react';
import { motion } from 'framer-motion';
import { FaGithub, FaLinkedin, FaEnvelope, FaPhone } from 'react-icons/fa';
import './Hero.css';

const Hero = () => {
  const [text, setText] = useState('');
  const [isDeleting, setIsDeleting] = useState(false);
  const [loopNum, setLoopNum] = useState(0);
  const [typingSpeed, setTypingSpeed] = useState(150);

  const roles = [
    'AI & Data Science Engineer',
    'Full Stack Developer',
    'Competitive Programmer',
    'Problem Solver'
  ];

  useEffect(() => {
    const handleType = () => {
      const i = loopNum % roles.length;
      const fullText = roles[i];

      setText(isDeleting 
        ? fullText.substring(0, text.length - 1)
        : fullText.substring(0, text.length + 1)
      );

      setTypingSpeed(isDeleting ? 50 : 150);

      if (!isDeleting && text === fullText) {
        setTimeout(() => setIsDeleting(true), 2000);
      } else if (isDeleting && text === '') {
        setIsDeleting(false);
        setLoopNum(loopNum + 1);
      }
    };

    const timer = setTimeout(handleType, typingSpeed);
    return () => clearTimeout(timer);
  }, [text, isDeleting, loopNum, typingSpeed, roles]);

  const containerVariants = {
    hidden: { opacity: 0 },
    visible: {
      opacity: 1,
      transition: {
        staggerChildren: 0.2
      }
    }
  };

  const itemVariants = {
    hidden: { y: 20, opacity: 0 },
    visible: {
      y: 0,
      opacity: 1,
      transition: { duration: 0.5 }
    }
  };

  return (
    <section className="hero" id="home">
      <div className="hero-background">
        <div className="grid-pattern"></div>
        <div className="gradient-orb orb-1"></div>
        <div className="gradient-orb orb-2"></div>
      </div>
      
      <motion.div 
        className="hero-content container"
        variants={containerVariants}
        initial="hidden"
        animate="visible"
      >
        <div className="hero-layout">
          <div className="hero-text-section">
            <motion.div className="hero-tag" variants={itemVariants}>
              <span className="tag-dot"></span>
              <span>Welcome to my portfolio</span>
            </motion.div>

            <motion.h1 variants={itemVariants}>
              Hi, I'm <span className="name-highlight">Gowtham M</span>
            </motion.h1>

            <motion.div className="typing-wrapper" variants={itemVariants}>
              <span className="typing-text">{text}</span>
              <span className="cursor">|</span>
            </motion.div>

            <motion.p className="hero-description" variants={itemVariants}>
              Analytical B.Tech graduate specializing in AI and Data Science.
              Passionate about solving complex problems through code and innovation.
            </motion.p>

            <motion.div className="hero-stats" variants={itemVariants}>
              <div className="stat-box">
                <h3>1000+</h3>
                <p>Problems Solved</p>
              </div>
              <div className="stat-box">
                <h3>8.92</h3>
                <p>CGPA</p>
              </div>
              <div className="stat-box">
                <h3>10+</h3>
                <p>Projects</p>
              </div>
            </motion.div>

            <motion.div className="hero-buttons" variants={itemVariants}>
              <a href="#projects" className="btn btn-primary">
                <span>View My Work</span>
                <svg width="20" height="20" viewBox="0 0 20 20" fill="none">
                  <path d="M7.5 15L12.5 10L7.5 5" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
                </svg>
              </a>
              <a href="#contact" className="btn btn-secondary">
                <span>Get In Touch</span>
              </a>
            </motion.div>

            <motion.div className="hero-social" variants={itemVariants}>
              <a href="https://github.com/GowthamGowri-11" target="_blank" rel="noopener noreferrer" aria-label="GitHub">
                <FaGithub />
              </a>
              <a href="https://linkedin.com/in/gowtham-m-0a83353771" target="_blank" rel="noopener noreferrer" aria-label="LinkedIn">
                <FaLinkedin />
              </a>
              <a href="mailto:kit28.24bad049@gmail.com" aria-label="Email">
                <FaEnvelope />
              </a>
              <a href="tel:+918154505751" aria-label="Phone">
                <FaPhone />
              </a>
            </motion.div>
          </div>

          <motion.div 
            className="hero-image-section"
            initial={{ opacity: 0, scale: 0.8, rotateY: -20 }}
            animate={{ opacity: 1, scale: 1, rotateY: 0 }}
            transition={{ duration: 1, delay: 0.5 }}
          >
            <div className="hero-image-wrapper">
              <div className="hero-image-container">
                <img 
                  src="/profile.png" 
                  alt="Gowtham M - AI & Data Science Engineer" 
                  className="hero-profile-image"
                />
              </div>
              <div className="hero-image-decoration">
                <div className="decoration-circle circle-1"></div>
                <div className="decoration-circle circle-2"></div>
                <div className="decoration-circle circle-3"></div>
              </div>
            </div>
          </motion.div>
        </div>
      </motion.div>

      <motion.div 
        className="scroll-indicator"
        initial={{ opacity: 0, y: -20 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ delay: 2, duration: 0.8 }}
      >
        <div className="mouse">
          <div className="mouse-wheel"></div>
        </div>
        <span>Scroll Down</span>
      </motion.div>
    </section>
  );
};

export default Hero;
